  1→import { getFloorElevation } from '@/domain/floorModels';
  2→import { getSlabBottomLevel } from '@/elevations/slab';
  3→import { getBeamRenderData } from '@/geometry/beamGeometry';
  4→import { isValidSlabBoundary } from '@/geometry/slabGeometry';
  5→import { getStairRenderData } from '@/geometry/stairGeometry';
  6→import { wallDirection, wallLength, wallOutline } from '@/geometry/wallGeometry';
  7→import { buildWallPreviewContexts, buildWallSolidSegments } from './wallPreviewContext';
  8→
  9→const DOOR_INSERT_THICKNESS_MIN = 35;
 10→const DOOR_INSERT_THICKNESS_MAX = 70;
 11→const WINDOW_INSERT_THICKNESS_MIN = 45;
 12→const WINDOW_INSERT_THICKNESS_MAX = 90;
 13→
 14→function createBoundsFromPoints(points, baseElevation, topElevation) {
 15→  if (!points?.length) {
 16→    return {
 17→      minX: 0,
 18→      maxX: 0,
 19→      minY: 0,
 20→      maxY: 0,
 21→      minElevation: baseElevation,
 22→      maxElevation: topElevation,
 23→    };
 24→  }
 25→
 26→  return {
 27→    minX: Math.min(...points.map((point) => point.x)),
 28→    maxX: Math.max(...points.map((point) => point.x)),
 29→    minY: Math.min(...points.map((point) => point.y)),
 30→    maxY: Math.max(...points.map((point) => point.y)),
 31→    minElevation: baseElevation,
 32→    maxElevation: topElevation,
 33→  };
 34→}
 35→
 36→function createPrismDescriptor(id, kind, outline, baseElevation, height, metadata = {}) {
 37→  const topElevation = baseElevation + height;
 38→  return {
 39→    id,
 40→    kind,
 41→    geometry: 'prism',
 42→    outline: outline.map((point) => ({ x: point.x, y: point.y })),
 43→    baseElevation,
 44→    height,
 45→    materialKey: metadata.materialKey || kind,
 46→    metadata,
 47→    bounds: createBoundsFromPoints(outline, baseElevation, topElevation),
 48→  };
 49→}
 50→
 51→function createLinearBoxDescriptor(id, kind, startPoint, endPoint, width, baseElevation, height, metadata = {}) {
 52→  const outline = wallOutline({
 53→    start: { x: startPoint.x, y: startPoint.y },
 54→    end: { x: endPoint.x, y: endPoint.y },
 55→    thickness: width,
 56→  });
 57→  const direction = wallDirection({
 58→    start: { x: startPoint.x, y: startPoint.y },
 59→    end: { x: endPoint.x, y: endPoint.y },
 60→  });
 61→  const topElevation = baseElevation + height;
 62→
 63→  return {
 64→    id,
 65→    kind,
 66→    geometry: 'box',
 67→    center: {
 68→      x: (startPoint.x + endPoint.x) / 2,
 69→      y: (startPoint.y + endPoint.y) / 2,
 70→    },
 71→    size: {
 72→      x: wallLength({ start: startPoint, end: endPoint }),
 73→      y: height,
 74→      z: width,
 75→    },
 76→    rotation: Math.atan2(direction.y, direction.x),
 77→    baseElevation,
 78→    materialKey: metadata.materialKey || kind,
 79→    metadata,
 80→    bounds: createBoundsFromPoints(outline, baseElevation, topElevation),
 81→  };
 82→}
 83→
 84→function createBoxDescriptor(id, kind, center, size, baseElevation, rotation = 0, metadata = {}) {
 85→  const halfX = size.x / 2;
 86→  const halfZ = size.z / 2;
 87→  const cos = Math.cos(rotation);
 88→  const sin = Math.sin(rotation);
 89→  const corners = [
 90→    { x: -halfX, y: -halfZ },
 91→    { x: halfX, y: -halfZ },
 92→    { x: halfX, y: halfZ },
 93→    { x: -halfX, y: halfZ },
 94→  ].map((point) => ({
 95→    x: center.x + (point.x * cos - point.y * sin),
 96→    y: center.y + (point.x * sin + point.y * cos),
 97→  }));
 98→
 99→  return {
100→    id,
101→    kind,
102→    geometry: 'box',
103→    center: { x: center.x, y: center.y },
104→    size,
105→    rotation,
106→    baseElevation,
107→    materialKey: metadata.materialKey || kind,
108→    metadata,
109→    bounds: createBoundsFromPoints(corners, baseElevation, baseElevation + size.y),
110→  };
111→}
112→
113→function createStairDescriptor(stair, floorLevel, floorId) {
114→  const renderData = getStairRenderData(stair);
115→  if (!renderData?.outline?.length) return null;
116→
117→  return {
118→    id: stair.id,
119→    kind: 'stair',
120→    geometry: 'stair',
121→    startPoint: { ...stair.startPoint },
122→    width: stair.width,
123→    numberOfRisers: stair.numberOfRisers,
124→    riserHeight: stair.riserHeight,
125→    treadDepth: stair.treadDepth,
126→    angle: renderData.angle,
127→    baseElevation: floorLevel,
128→    materialKey: 'stair',
129→    metadata: {
130→      sourceId: stair.id,
131→      floorId,
132→    },
133→    bounds: createBoundsFromPoints(
134→      renderData.outline,
135→      floorLevel,
136→      floorLevel + renderData.totalRise
137→    ),
138→  };
139→}
140→
141→function buildWallObjects(wallContexts) {
142→  return wallContexts.flatMap((context) => (
143→    buildWallSolidSegments(context).map((segment) => createLinearBoxDescriptor(
144→      segment.id,
145→      'wall',
146→      segment.startPoint,
147→      segment.endPoint,
148→      segment.thickness,
149→      segment.baseElevation,
150→      segment.topElevation - segment.baseElevation,
151→      {
152→        sourceId: segment.wallId,
153→        floorId: segment.floorId,
154→        wallId: segment.wallId,
155→      }
156→    ))
157→  ));
158→}
159→
160→function buildSlabObjects(floor) {
161→  return (floor.slabs || [])
162→    .filter(slab => isValidSlabBoundary(slab.boundaryPoints))
163→    .map(slab => createPrismDescriptor(
164→      slab.id,
165→      'slab',
166→      slab.boundaryPoints,
167→      getSlabBottomLevel(slab),
168→      slab.thickness ?? 0,
169→      {
170→        sourceId: slab.id,
171→        floorId: floor.id,
172→      }
173→    ));
174→}
175→
176→function buildColumnObjects(floor, floorLevel) {
177→  return (floor.columns || []).map((column) => createBoxDescriptor(
178→    column.id,
179→    'column',
180→    { x: column.x, y: column.y },
181→    {
182→      x: column.width,
183→      y: column.height,
184→      z: column.depth,
185→    },
186→    floorLevel,
187→    (column.rotation || 0) * Math.PI / 180,
188→    {
189→      sourceId: column.id,
190→      floorId: floor.id,
191→    }
192→  ));
193→}
194→
195→function buildBeamObjects(floor) {
196→  return (floor.beams || [])
197→    .map((beam) => {
198→      const renderData = getBeamRenderData(beam, floor.columns || []);
199→      if (!renderData) return null;
200→
201→      return createLinearBoxDescriptor(
202→        beam.id,
203→        'beam',
204→        renderData.start,
205→        renderData.end,
206→        beam.width,
207→        beam.floorLevel - beam.depth,
208→        beam.depth,
209→        {
210→          sourceId: beam.id,
211→          floorId: floor.id,
212→        }
213→      );
214→    })
215→    .filter(Boolean);
216→}
217→
218→function getInsertThickness(kind, wallThickness) {
219→  if (kind === 'door') {
220→    return Math.max(
221→      DOOR_INSERT_THICKNESS_MIN,
222→      Math.min(wallThickness * 0.22, DOOR_INSERT_THICKNESS_MAX)
223→    );
224→  }
225→
226→  return Math.max(
227→    WINDOW_INSERT_THICKNESS_MIN,
228→    Math.min(wallThickness * 0.32, WINDOW_INSERT_THICKNESS_MAX)
229→  );
230→}
231→
232→function createOpeningInsertDescriptor(opening) {
233→  return createBoxDescriptor(
234→    opening.id,
235→    opening.kind,
236→    opening.centerPoint,
237→    {
238→      x: opening.visibleWidth,
239→      y: opening.visibleHeight,
240→      z: getInsertThickness(opening.kind, opening.wallThickness),
241→    },
242→    opening.visibleBaseElevation,
243→    opening.angle,
244→    {
245→      sourceId: opening.sourceId,
246→      floorId: opening.metadata.floorId,
247→      wallId: opening.wallId,
248→      openingKind: opening.kind,
249→    }
250→  );
251→}
252→
253→function buildDoorObjects(wallContexts) {
254→  return wallContexts
255→    .flatMap((context) => context.openings)
256→    .filter((opening) => opening.kind === 'door')
257→    .map((opening) => createOpeningInsertDescriptor(opening));
258→}
259→
260→function buildWindowObjects(wallContexts) {
261→  return wallContexts
262→    .flatMap((context) => context.openings)
263→    .filter((opening) => opening.kind === 'window')
264→    .map((opening) => {
265→      const desc = createOpeningInsertDescriptor(opening);
266→      desc.geometry = 'window';
267→      desc.windowType = opening.type || 'standard';
268→      desc.openDirection = opening.openDirection || 'left';
269→      return desc;
270→    });
271→}
272→
273→function buildStairObjects(floor, floorLevel) {
274→  return (floor.stairs || [])
275→    .map((stair) => createStairDescriptor(stair, floorLevel, floor.id))
276→    .filter(Boolean);
277→}
278→
279→function buildLandingObjects(floor, floorLevel) {
280→  return (floor.landings || []).map((landing) => createBoxDescriptor(
281→    landing.id,
282→    'landing',
283→    { x: landing.position.x, y: landing.position.y },
284→    {
285→      x: landing.width,
286→      y: landing.thickness ?? 200,
287→      z: landing.depth,
288→    },
289→    floorLevel + (landing.elevation || 0),
290→    (landing.rotation || 0) * Math.PI / 180,
291→    {
292→      sourceId: landing.id,
293→      floorId: floor.id,
294→    }
295→  ));
296→}
297→
298→export function buildFloorPreviewObjects(floor) {
299→  const floorLevel = getFloorElevation(floor);
300→  const wallContexts = buildWallPreviewContexts(floor, floorLevel);
301→
302→  return [
303→    ...buildSlabObjects(floor),
304→    ...buildWallObjects(wallContexts),
305→    ...buildColumnObjects(floor, floorLevel),
306→    ...buildBeamObjects(floor),
307→    ...buildStairObjects(floor, floorLevel),
308→    ...buildLandingObjects(floor, floorLevel),
309→    ...buildDoorObjects(wallContexts),
310→    ...buildWindowObjects(wallContexts),
311→  ];
312→}
