  1→import { distance, midpoint, rotate } from './point';
  2→import { pointInPolygon } from './polygon';
  3→
  4→/**
  5→ * Returns 4 corner points of the landing rectangle, rotated around its center.
  6→ * Order: top-left, top-right, bottom-right, bottom-left
  7→ * (where "top" = in the negative-y direction before rotation, matching plan-view convention)
  8→ */
  9→export function landingOutline(landing) {
 10→  const { position, width, depth, rotation = 0 } = landing;
 11→  if (!position) return [];
 12→
 13→  const halfW = width / 2;
 14→  const halfD = depth / 2;
 15→
 16→  // Corners before rotation (centered on position)
 17→  const corners = [
 18→    { x: position.x - halfW, y: position.y - halfD },
 19→    { x: position.x + halfW, y: position.y - halfD },
 20→    { x: position.x + halfW, y: position.y + halfD },
 21→    { x: position.x - halfW, y: position.y + halfD },
 22→  ];
 23→
 24→  if (rotation === 0) return corners;
 25→  return corners.map((c) => rotate(c, position, rotation));
 26→}
 27→
 28→/**
 29→ * Returns 4 named edges of the landing.
 30→ * Names follow the stair convention:
 31→ *   'top'    — width-axis edge at negative-y (before rotation)
 32→ *   'bottom' — width-axis edge at positive-y
 33→ *   'left'   — depth-axis edge at negative-x
 34→ *   'right'  — depth-axis edge at positive-x
 35→ */
 36→export function landingEdges(landing) {
 37→  const outline = landingOutline(landing);
 38→  if (outline.length < 4) return [];
 39→
 40→  const [tl, tr, br, bl] = outline;
 41→
 42→  function makeEdge(name, start, end) {
 43→    const mid = midpoint(start, end);
 44→    const dx = end.x - start.x;
 45→    const dy = end.y - start.y;
 46→    const len = Math.sqrt(dx * dx + dy * dy) || 1;
 47→    return {
 48→      name,
 49→      start,
 50→      end,
 51→      midpoint: mid,
 52→      normal: { x: -dy / len, y: dx / len },
 53→    };
 54→  }
 55→
 56→  return [
 57→    makeEdge('top', tl, tr),
 58→    makeEdge('right', tr, br),
 59→    makeEdge('bottom', br, bl),
 60→    makeEdge('left', bl, tl),
 61→  ];
 62→}
 63→
 64→export function landingContainsPoint(landing, point) {
 65→  const outline = landingOutline(landing);
 66→  if (outline.length < 3) return false;
 67→  return pointInPolygon(point, outline);
 68→}
 69→
 70→export function landingBounds(landing) {
 71→  const outline = landingOutline(landing);
 72→  if (!outline.length) return null;
 73→  const xs = outline.map((p) => p.x);
 74→  const ys = outline.map((p) => p.y);
 75→  return {
 76→    minX: Math.min(...xs),
 77→    maxX: Math.max(...xs),
 78→    minY: Math.min(...ys),
 79→    maxY: Math.max(...ys),
 80→  };
 81→}
 82→
 83→export function getLandingRenderData(landing) {
 84→  const outline = landingOutline(landing);
 85→  if (outline.length < 3) return null;
 86→  const edges = landingEdges(landing);
 87→  const bounds = landingBounds(landing);
 88→  return {
 89→    outline,
 90→    edges,
 91→    bounds,
 92→    center: landing.position,
 93→  };
 94→}
 95→
 96→/**
 97→ * Snap a point to the nearest landing edge midpoint within snapDist.
 98→ * Returns { point, landingId, edge } or null.
 99→ */
100→export function snapToLandingEdge(point, landings, snapDist) {
101→  let best = null;
102→  let bestDist = snapDist;
103→
104→  for (const landing of (landings || [])) {
105→    const edges = landingEdges(landing);
106→    for (const edge of edges) {
107→      const d = distance(point, edge.midpoint);
108→      if (d < bestDist) {
109→        bestDist = d;
110→        best = {
111→          point: { x: edge.midpoint.x, y: edge.midpoint.y },
112→          landingId: landing.id,
113→          edge: edge.name,
114→        };
115→      }
116→    }
117→  }
118→
119→  return best;
120→}
121→
122→/**
123→ * Sync a stair's start/end point to the landing edge midpoint when a landing moves.
124→ * Returns an updated copy of the stair, or the original if no attachments.
125→ */
126→export function syncStairLandingAttachment(stair, landings) {
127→  let updated = false;
128→  let nextStair = { ...stair };
129→
130→  if (stair.startLandingAttachment) {
131→    const landing = landings.find((l) => l.id === stair.startLandingAttachment.landingId);
132→    if (landing) {
133→      const edges = landingEdges(landing);
134→      const edge = edges.find((e) => e.name === stair.startLandingAttachment.edge);
135→      if (edge) {
136→        nextStair.startPoint = { x: edge.midpoint.x, y: edge.midpoint.y };
137→        updated = true;
138→      }
139→    }
140→  }
141→
142→  if (stair.endLandingAttachment) {
143→    const landing = landings.find((l) => l.id === stair.endLandingAttachment.landingId);
144→    if (landing) {
145→      const edges = landingEdges(landing);
146→      const edge = edges.find((e) => e.name === stair.endLandingAttachment.edge);
147→      if (edge) {
148→        // Recompute direction angle so the end point lands on the edge midpoint
149→        const run = Math.max(0, (stair.numberOfRisers || 0) * (stair.treadDepth || 0));
150→        if (run > 0) {
151→          const startPt = nextStair.startPoint;
152→          const dx = edge.midpoint.x - startPt.x;
153→          const dy = edge.midpoint.y - startPt.y;
154→          const angle = (Math.atan2(dy, dx) * 180) / Math.PI;
155→          nextStair.direction = { angle };
156→          updated = true;
157→        }
158→      }
159→    }
160→  }
161→
162→  return updated ? nextStair : stair;
163→}
164→
165→/**
166→ * Compute landing elevation from connected stairs.
167→ * Uses the first stair whose end lands on this landing (total rise from that stair).
168→ * Falls back to 0.
169→ */
170→export function computeLandingElevation(landing, stairs, floorLevel = 0) {
171→  for (const stair of (stairs || [])) {
172→    if (stair.endLandingAttachment?.landingId === landing.id) {
173→      const totalRise = Math.max(0, (stair.numberOfRisers || 0) * (stair.riserHeight || 0));
174→      return floorLevel + totalRise;
175→    }
176→    if (stair.startLandingAttachment?.landingId === landing.id) {
177→      return floorLevel;
178→    }
179→  }
180→  return floorLevel;
181→}
